mapper.select:
SELECT id, email, phone, nickname, real_name, avatar_url,
       role, status, email_verified, phone_verified, last_login_at,
       created_at, updated_at
FROM users WHERE role = #{role}
ORDER BY created_at DESC
LIMIT #{offset}, #{size}

SELECT EXISTS(
    SELECT 1
    FROM waitlist_order
    WHERE user_id = #{userId}
      AND status = 'WAITING'
)

SELECT EXISTS(
    SELECT 1
    FROM refund_record rr
    JOIN ticket_order o ON rr.order_id = o.id
    WHERE o.user_id = #{userId}
      AND rr.status NOT IN ('SUCCESS','FAILED','CANCELLED')
) OR EXISTS(
    SELECT 1
    FROM change_record cr
    JOIN ticket_order o ON cr.order_id = o.id
    WHERE o.user_id = #{userId}
      AND cr.status NOT IN ('SUCCESS','FAILED','CANCELLED')
)
